package settings

import (
	"context"

	"google.golang.org/grpc"

	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/generated/protos/types/devvit/actor/settings"
	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/grpc/proxyutil"
)

type AppSettingsProxy struct {
	settings.UnimplementedAppSettingsServer
	client settings.AppSettingsClient
}

func init() {
	proxyutil.Register(&settings.AppSettings_ServiceDesc, NewAppSettingsProxy)
}
func NewAppSettingsProxy(cc grpc.ClientConnInterface) settings.AppSettingsServer {
	return &AppSettingsProxy{client: settings.NewAppSettingsClient(cc)}
}
func (p *AppSettingsProxy) GetAppSettingsFields(ctx context.Context, in *settings.GetFieldsRequest) (*settings.GetFieldsResponse, error) {
	return proxyutil.ProxyMethod[settings.GetFieldsRequest, settings.GetFieldsResponse](p.client.GetAppSettingsFields)(ctx, in)
}
func (p *AppSettingsProxy) ValidateAppForm(ctx context.Context, in *settings.ValidateFormRequest) (*settings.ValidateFormResponse, error) {
	return proxyutil.ProxyMethod[settings.ValidateFormRequest, settings.ValidateFormResponse](p.client.ValidateAppForm)(ctx, in)
}
